<template>
  <el-container>
      <el-button @click="askAI">咨询</el-button>
      <el-button @click="askAIImage">图片分析</el-button>
      {{ tempMessage }}
  </el-container>
</template>

<script setup name="Index">
const tempMessage = ref('123')
const askAI = async () => {
  const response = await fetch('http://192.168.0.99:9002/api/smart/ask-sse', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({question: "推荐一款流量计"})
  });

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder();

  while (true) {
    const {done, value} = await reader.read();
    if (done) break;

    const chunk = decoder.decode(value);
    // 解析 chunk 中的 "data: ..." 格式
    // 将内容追加到聊天框
    console.log(chunk);
    tempMessage.value += chunk;
  }
}
const askAIImage = async () => {
  // // 1. 获取 Echarts 实例
  // const chartInstance = echarts.getInstanceByDom(document.getElementById('main'));

// // 2. 生成图片 (DataURL)
//   const dataUrl = chartInstance.getDataURL({
//     type: 'png',
//     pixelRatio: 2, // 提高清晰度，方便 AI 识别小字
//     backgroundColor: '#fff' // 强制白底，节省 Token 且清晰
//   });

// 3. 提取 Base64 字符串 (去掉 "data:image/png;base64," 前缀)
//   const base64String = dataUrl.split(',')[1];
  const base64String = ''

// // 4. 发送给后端
//   const response = await fetch('http://192.168.0.99:9002/api/automatic-meter-reading/analyze-meter-chart', {
//     method: 'POST',
//     headers: {'Content-Type': 'application/json'},
//     body: JSON.stringify({
//       imageBase64: base64String,
//       deviceContext: {medium: '水', type: '电磁流量计'}
//     })
//   });

//   if (!response.ok) {
//     // 如果出错，尝试读取错误信息（如果有的话）
//     let errorMsg = `HTTP error! status: ${response.status}`;
//     try {
//       const errorData = await response.json(); // 尝试解析错误响应中的 JSON
//       errorMsg += `, message: ${JSON.stringify(errorData)}`;
//     } catch (e) {
//       // 如果错误响应不是 JSON，则忽略
//     }
//     throw new Error(errorMsg);
//   }
//
// // 【关键步骤】解析响应体为 JSON 对象
//   const data = await response.json();
//
//   console.log('解析后的数据:', data);
// // 现在你可以使用 data 中的具体字段了，例如：
// // console.log(data.result);
//   tempMessage.value = data.data.answer
  const abortController = new AbortController();
  const response = await fetch('http://192.168.0.99:9002/api/automatic-meter-reading/analyze-meter-chart-sse', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({
      imageBase64: base64String,
      deviceContext: {medium: '水', type: '电磁流量计'}
    }),
    signal: abortController.signal
  });
  if (!response.ok) { throw new Error(`HTTP ${response.status}`); }
  const reader = response.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let buffer = ''; // 缓存未处理完的数据块

  // 定义递归读取函数
  const processText = ({done, value}) => {
    if (done) {
      return;
    }

    // 解码当前数据分片并拼接入缓存
    buffer += decoder.decode(value, {stream: true});

    // SSE 以换行符分割消息
    const lines = buffer.split('\n');
    // 最后一行可能不完整，留到下次处理
    buffer = lines.pop() || '';

    for (const line of lines) {
      const trimmedLine = line.trim();
      if (!trimmedLine || !trimmedLine.startsWith('data: ')) continue;

      const dataPayload = trimmedLine.slice(6).trim();

      // 情况 A: 结束标记
      if (dataPayload === '[DONE]') {
        return; // 退出循环，不执行 pump
      }

      // 情况 B: 报错标记
      if (dataPayload.startsWith('ERROR:')) {
        return;
      }

      // 情况 C: 正常文本块
      try {
        // 后端使用 JsonSerializer.Serialize 会包装双引号并转义换行符
        // JSON.parse 将其还原为真正的字符串 (如 "你好\n\n" )
        const cleanText = JSON.parse(dataPayload);
        tempMessage.value += cleanText;
      } catch (e) {
        // 兜底：如果不是标准 JSON 字符串，则按原样处理
        tempMessage.value += dataPayload;
      }
    }

    reader.read().then(processText);
  };
  reader.read().then(processText);
  
}

</script>

